mapper.select:
SELECT u.user_id, u.nick_name, r.role_key, a.phone, a.real_name_verified, (SELECT COUNT(*) FROM sys_user_building ub WHERE ub.user_id = u.user_id AND ub.status = 1) AS building_count FROM sys_user_role ur JOIN sys_user u ON u.user_id = ur.user_id JOIN sys_role r ON r.role_id = ur.role_id JOIN sys_dept d ON d.dept_id = u.dept_id LEFT JOIN t_account a ON a.account_id = u.account_id WHERE r.role_key = #{roleKey} AND u.status = '0'
AND d.tenant_id = #{tenantId}
ORDER BY u.user_id ASC

SELECT u.user_id, u.nick_name, r.role_key, a.phone, a.real_name_verified, (SELECT COUNT(*) FROM sys_user_building ub WHERE ub.user_id = u.user_id AND ub.status = 1) AS building_count FROM sys_user_role ur JOIN sys_user u ON u.user_id = ur.user_id JOIN sys_role r ON r.role_id = ur.role_id JOIN sys_dept d ON d.dept_id = u.dept_id LEFT JOIN t_account a ON a.account_id = u.account_id WHERE r.role_key IN ('GRID_OPERATOR','VOLUNTEER','OWNER_REPRESENTATIVE') AND u.status = '0' AND ( u.nick_name ILIKE CONCAT('%', #{keyword}, '%') OR a.phone = #{keyword} OR a.phone LIKE CONCAT('%', #{keyword}) )
AND d.tenant_id = #{tenantId}
ORDER BY u.user_id ASC LIMIT #{limit}

SELECT ub.user_id, u.nick_name, r.role_key FROM sys_user_building ub JOIN sys_user u ON u.user_id = ub.user_id LEFT JOIN sys_user_role ur ON ur.user_id = ub.user_id LEFT JOIN sys_role r ON r.role_id = ur.role_id WHERE ub.building_id = #{buildingId} AND ub.status = 1
AND ub.tenant_id = #{tenantId}
ORDER BY ub.user_id ASC

mapper.update:
UPDATE sys_user_building
SET status = 1, assigned_by = #{assignedBy}, assigned_at = now(), revoke_reason = NULL
WHERE assignment_id = #{assignmentId}

UPDATE sys_user_building
SET status = 2, revoke_reason = #{revokeReason}
WHERE user_id = #{userId} AND building_id = #{buildingId} AND status = 1

mapper.select:
SELECT EXISTS(
    SELECT 1 FROM sys_user_role ur
    JOIN sys_role r ON r.role_id = ur.role_id
    JOIN sys_user u ON u.user_id = ur.user_id
    JOIN sys_dept d ON d.dept_id = u.dept_id
    WHERE ur.user_id = #{userId} AND r.role_key = #{roleKey}

        AND d.tenant_id = #{tenantId}

)
